#!/usr/bin/env python3\nimport yaml\nfrom pydantic import BaseModel, Field\nfrom typing import List\n\nclass Truth(BaseModel):\n    num: int = Field(..., description=\"Truth number\")\n    truth: str = Field(..., description=\"Core truth statement\")\n    when: str = Field(..., description=\"When applied\")\n    ex: str = Field(..., description=\"Example\")\n\nclass Drive(BaseModel):\n    drive: str = Field(..., description=\"Drive name\")\n    essence: str = Field(..., description=\"Essence\")\n    expr: str = Field(..., description=\"Expression\")\n    ex: str = Field(..., description=\"Example\")\n\nclass Soul(BaseModel):\n    name: str\n    truths: List[Truth]\n    drives: List[Drive]\n\n# Load from workspace SOUL.md (adjust path if run from vault)\nwith open('/home/simon/.openclaw/workspace/SOUL.md', 'r') as f:\n    data = yaml.safe_load(f)\n\n# Extract model data (skip schema/header)\nsoul_data = {}\nfor key, value in data.items():\n    if isinstance(value, dict) and 'truth' in str(value).lower():\n        soul_data['truths'] = value.get('truths', [])\n    elif isinstance(value, dict) and 'drive' in str(value).lower():\n        soul_data['drives'] = value.get('drives', [])\n    elif key == 'name':\n        soul_data['name'] = value\n\nsoul = Soul.model_validate(soul_data)\nprint(f\"Loaded SOUL: {soul.name}\")\nprint(f\"Truth #19: {soul.truths[19].truth if len(soul.truths) > 19 else 'Not found'}\")\nprint(\"P0 Success: Schema + Loader working.\")